#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define W 2400
#define H 1800
#define INF 1e20

typedef struct { double x, y, z; } Vec;

Vec v(double x, double y, double z) {
    Vec r = {x, y, z};
    return r;
}

double dot(Vec a, Vec b) { return a.x*b.x + a.y*b.y + a.z*b.z; }
Vec sub(Vec a, Vec b) { return v(a.x-b.x, a.y-b.y, a.z-b.z); }
Vec add(Vec a, Vec b) { return v(a.x+b.x, a.y+b.y, a.z+b.z); }
Vec mul(Vec a, double s) { return v(a.x*s, a.y*s, a.z*s); }
Vec norm(Vec a) {
    double l = sqrt(dot(a,a));
    return v(a.x/l, a.y/l, a.z/l);
}
double clamp(double x) { return x < 0 ? 0 : (x > 255 ? 255 : x); }

int main() {
    FILE *f = fopen("reconstructed.ppm", "w");
    fprintf(f, "P3\n%d %d\n255\n", W, H);

    // Camera parameters
    Vec cam_pos = v(0, 1.7, 5);
    Vec cam_target = v(0, 0, 0);

    Vec cz = norm(sub(cam_target, cam_pos));
    Vec up = v(0, 1, 0);
    Vec cx = norm(v(up.y*cz.z - up.z*cz.y, up.z*cz.x - up.x*cz.z, up.x*cz.y - up.y*cz.x));
    Vec cy = v(cz.y*cx.z - cz.z*cx.y, cz.z*cx.x - cz.x*cx.z, cz.x*cx.y - cz.y*cx.x);

    // Sphere
    Vec sphere_pos = v(0, 0.5, 0);
    double sphere_r = 1.0;
    Vec sphere_col = v(1.0, 0.2, 0.2); // Reddish

    // Light
    Vec light_pos = v(5, 5, 5);
    Vec light_col = v(1, 1, 1);

    // Ground plane
    double ground_y = 0;  // y=0 is ground

    double aspect = (double)W / H;
    double fov = 1.0;  // focal length

    for (int y = 0; y < H; y++) {
        for (int x = 0; x < W; x++) {
            double u = (2.0 * x / W - 1.0) * aspect;
            double vv = -(2.0 * y / H - 1.0);

            Vec dir = norm(v(u, vv, -fov));
            // Transform to world space
            Vec wdir = v(cx.x*dir.x + cy.x*dir.y + cz.x*dir.z,
                         cx.y*dir.x + cy.y*dir.y + cz.y*dir.z,
                         cx.z*dir.x + cy.z*dir.y + cz.z*dir.z);

            double r, g, b;

            // Check sphere intersection
            Vec oc = sub(cam_pos, sphere_pos);
            double a = dot(wdir, wdir);
            double b_ = 2 * dot(oc, wdir);
            double c = dot(oc, oc) - sphere_r * sphere_r;
            double disc = b_*b_ - 4*a*c;

            if (disc > 0) {
                double t = (-b_ - sqrt(disc)) / (2 * a);
                if (t > 0.001) {
                    Vec pt = add(cam_pos, mul(wdir, t));
                    Vec n = norm(sub(pt, sphere_pos));
                    Vec L = norm(sub(light_pos, pt));
                    double diff = dot(n, L);
                    if (diff < 0) diff = 0;

                    Vec V = mul(wdir, -1);
                    Vec H = norm(add(L, V));
                    double spec = dot(n, H);
                    if (spec < 0) spec = 0;
                    spec = pow(spec, 20);

                    r = clamp(sphere_col.x * (0.2 + 0.8 * diff) * 255 + spec * 200);
                    g = clamp(sphere_col.y * (0.2 + 0.8 * diff) * 255 + spec * 200);
                    b = clamp(sphere_col.z * (0.2 + 0.8 * diff) * 255 + spec * 200);

                    fprintf(f, "%d %d %d\n", (int)r, (int)g, (int)b);
                    continue;
                }
            }

            // Check ground plane intersection
            if (wdir.y < 0) {
                double t = -(cam_pos.y - ground_y) / wdir.y;
                if (t > 0) {
                    Vec pt = add(cam_pos, mul(wdir, t));
                    int ix = (int)(floor(pt.x * 2) + 1000);
                    int iz = (int)(floor(pt.z * 2) + 1000);
                    double col = ((ix + iz) & 1) ? 152 : 67;

                    // Check shadow
                    Vec L = norm(sub(light_pos, pt));
                    // Check sphere shadow
                    Vec sh_oc = sub(pt, sphere_pos);
                    double sh_a = dot(L, L);
                    double sh_b = 2 * dot(sh_oc, L);
                    double sh_c = dot(sh_oc, sh_oc) - sphere_r * sphere_r;
                    double sh_disc = sh_b*sh_b - 4*sh_a*sh_c;
                    if (sh_disc > 0) {
                        double sh_t = (-sh_b - sqrt(sh_disc)) / (2 * sh_a);
                        if (sh_t > 0.001) {
                            col *= 0.3; // shadow
                        }
                    }

                    r = g = b = clamp(col);
                    fprintf(f, "%d %d %d\n", (int)r, (int)g, (int)b);
                    continue;
                }
            }

            // Sky
            double t = 0.5 + 0.5 * wdir.y;
            double sky_r = 146 + (191 - 146) * (1 - t);
            double sky_g = 190 + (217 - 190) * (1 - t);
            r = clamp(sky_r);
            g = clamp(sky_g);
            b = 255;
            fprintf(f, "%d %d %d\n", (int)r, (int)g, (int)b);
        }
    }

    fclose(f);
    return 0;
}
EOF
